# ==========================================
# SERVIDOR
# ==========================================
server &lt;- function(input, output, session) {

  validacion &lt;- eventReactive(input$verificar, {
    list(
      a = list(consulta = input$especie_a, match = gbif_name_match(input$especie_a)),
      b = list(consulta = input$especie_b, match = gbif_name_match(input$especie_b))
    )
  })

  output$validacion_nombres &lt;- renderUI({
    v &lt;- validacion()
    tagList(lapply(list(v$a, v$b), function(r) {
      m &lt;- r$match
      if (is.null(m) || is.null(m$matchType) || m$matchType == "NONE") {
        div(class = "alert alert-danger", style = "padding:6px; font-size:0.85em; margin-top:4px;",
            paste0("❌ '", r$consulta, "' no se encontró en el backbone de GBIF."))
      } else if (m$matchType == "EXACT") {
        div(class = "alert alert-success", style = "padding:6px; font-size:0.85em; margin-top:4px;",
            paste0("✅ '", r$consulta, "' reconocido como ", m$scientificName, " (", m$status, ")"))
      } else {
        div(class = "alert alert-warning", style = "padding:6px; font-size:0.85em; margin-top:4px;",
            paste0("⚠️ '", r$consulta, "' es una coincidencia aproximada. GBIF sugiere: ", m$canonicalName, "."))
      }
    }))
  })

  resultado &lt;- eventReactive(input$procesar, {
    req(input$especie_a, input$especie_b)
    t_inicio &lt;- Sys.time()
    withProgress(message = "Consultando GloBI...", value = 0.1, {
      general &lt;- buscar_evidencia_general(input$especie_a, input$especie_b)
      message(paste0("[timing] Evidencia general completa: ",
                      round(as.numeric(Sys.time() - t_inicio, units = "secs"), 1), "s (fuente: ", general$fuente, ")"))
      incProgress(0.5, detail = "Evidencia general lista")

      t_enfocada &lt;- Sys.time()
      rasgos_elegidos &lt;- c(input$cb_sector, input$cb_eco_evolutiva, input$cb_historia_vida, input$cb_aplicado)
      enfocada &lt;- buscar_evidencia_enfocada(input$especie_a, input$especie_b, rasgos_elegidos)
      message(paste0("[timing] Búsqueda enfocada: ",
                      round(as.numeric(Sys.time() - t_enfocada, units = "secs"), 1), "s"))
      incProgress(0.3, detail = "Listo")

      message(paste0("[timing] TOTAL: ", round(as.numeric(Sys.time() - t_inicio, units = "secs"), 1), "s"))
      list(general = general, enfocada = enfocada)
    })
  })

  output$ficha_resultado &lt;- renderUI({
    res &lt;- resultado()
    req(res)
    g &lt;- res$general
    e &lt;- res$enfocada

    wellPanel(
      style = "background: #ffffff; border: 1px solid #d1d5db;",
      tags$h4("Ficha de Interacción"),
      tags$p(tags$strong("Especie A: "), input$especie_a, tags$br(),
             tags$strong("Especie B: "), input$especie_b),
      tags$hr(),
      tags$h5("Evidencia general"),
      tags$pre(
        paste0(
          "--- METADATA PROFILE (FAIR/CARE) ---\n",
          "Fuente: ", g$fuente, "\n",
          "Consulta: ", g$consulta, "\n",
          "Nivel: ", g$nivel, "\n",
          "Citas encontradas: ", length(g$citas), "\n",
          "Fecha de consulta: ", format(Sys.time(), "%Y-%m-%d %H:%M %Z")
        )
      ),
      if (length(g$citas) == 0) {
        tags$p("No se encontraron citas que mencionen a ninguna de las dos especies.")
      } else {
        tags$ol(lapply(g$citas, function(c) tags$li(HTML(c))))
      },
      if (!is.null(e)) tagList(
        tags$hr(),
        tags$h5(paste0("Evidencia enfocada en: ", paste(e$rasgos, collapse = ", "))),
        tags$p(style = "font-size: 0.8em; color: #64748b;", paste0("Consulta: ", e$consulta)),
        if (length(e$citas) == 0) {
          tags$p("No se encontraron citas enfocadas en estos rasgos para este par de especies.")
        } else {
          tags$ol(lapply(e$citas, function(c) tags$li(HTML(c))))
        }
      ),
      br(),
      downloadButton("descargar_citas", "Descargar todas las citas (.csv)", class = "btn-outline-secondary")
    )
  })

  output$descargar_citas &lt;- downloadHandler(
    filename = function() paste0("interdomestic_citas_", Sys.Date(), ".csv"),
    content = function(file) {
      res &lt;- resultado()
      req(res)
      g &lt;- res$general
      e &lt;- res$enfocada

      filas_generales &lt;- if (length(g$citas) &gt; 0) {
        data.frame(especie_a = input$especie_a, especie_b = input$especie_b,
                   bloque = "general", fuente = g$fuente, detalle = g$nivel, cita = g$citas,
                   stringsAsFactors = FALSE)
      } else NULL

      filas_enfocadas &lt;- if (!is.null(e) && length(e$citas) &gt; 0) {
        data.frame(especie_a = input$especie_a, especie_b = input$especie_b,
                   bloque = "enfocada", fuente = "Crossref",
                   detalle = paste(e$rasgos, collapse = ", "), cita = e$citas,
                   stringsAsFactors = FALSE)
      } else NULL

      df &lt;- bind_rows(filas_generales, filas_enfocadas)
      write.csv(df, file, row.names = FALSE)
    }
  )
}

shinyApp(ui, server)

Distribución geográfica de especies: la co-existencia de especies en un espacio y tiempo brinda un marco regional para la ocurrencia de interacciones entre especies, incluyéndonos.
La co-existencia regional de especies forma un marco de co-evolución entre especies, o mosaico geográfico de co-evolución, en donde las especies evolucionan en función de las características de la interacción en el paisaje. La visualización de la distribución de especies de la vida silvestre, mediante mapas, ayuda en la interpretación multidisciplinar de la consulta.









⏳ Primera carga: el entorno estadístico (R) se descarga y arranca completo dentro de la ventana de tu navegador — puede tardar un minuto la primera vez. Después de esa carga inicial, la app responde al instante. ¡Gracias por la paciencia!









Tip💡 Cómo usar este apéndice interactivo






Escribe una o más especies, un nombre científico por línea (precargado con Panthera onca y Puma concolor como ejemplo).
Verifica los nombres con el botón “🔎 Verificar nombres” antes de sincronizar — se confirma si GBIF reconoce cada nombre tal cual, si hay una coincidencia aproximada, o si no lo encuentra (corregir nombre).
Define cuántos registros traer por especie con el campo “Registros máx.”
Aprieta “Sincronizar Distribución Geográfica” para consultar GBIF y ver los puntos de ocurrencia en el mapa — cada especie con su propio color.
Explorá el mapa (zoom, desplazamiento, popups con el nombre al hacer clic). Puedes descargar los datos crudos en .csv.










Importante🔎 Si dudas del nombre científico





Para que la búsqueda funcione bien, necesitas el nombre tal como lo reconoce el backbone taxonómico de GBIF. Si tienes dudas, verificalo antes en:

GBIF Species Search — la fuente misma que consulta esta app.
iNaturalist — identificación asistida por comunidad y por IA; puerta de entrada sugerida si solo tienes una foto o un nombre común.
Tropicos.org (Missouri Botanical Garden) — referencia nomenclatural para plantas.
Catalogue of Life — checklist taxonómico global de consenso, punto de partida para cualquier grupo.
Open Tree of Life — árbol filogenético navegable, mantenido activamente (el histórico Tree of Life Web Project está fuera de línea desde noviembre 2025).




